"use client";

import { useState } from "react";
import Link from "next/link";
import {
  ArrowRight,
  Bot,
  CheckCircle2,
  ExternalLink,
  Layers3,
  Mail,
  MonitorSmartphone,
  Phone,
  Send,
  Sparkles,
  Workflow
} from "lucide-react";
import { AppShell } from "@/components/app-shell";
import { Button } from "@/components/ui/button";

const services = [
  {
    title: "Website and app rebuilds",
    description:
      "Turn dated, confusing, or hard-to-maintain digital properties into modern experiences that are clear, fast, and built around the way your business actually works.",
    icon: MonitorSmartphone
  },
  {
    title: "AI-first business systems",
    description:
      "Map the messy parts of your operation, then design practical AI workflows, automations, and internal tools that save time without adding chaos.",
    icon: Bot
  },
  {
    title: "Brand and content infrastructure",
    description:
      "Shape the message, visuals, content model, and publishing rhythm so your website can support campaigns, sales conversations, and everyday credibility.",
    icon: Layers3
  },
  {
    title: "Implementation leadership",
    description:
      "Bridge strategy and execution with technical direction, vendor coordination, launch planning, and the judgment to keep the work moving.",
    icon: Workflow
  }
];

const process = ["Audit what exists", "Clarify the business goal", "Design the new system", "Build and launch", "Improve with real feedback"];

const projects = [
  {
    name: "GrabTheTab",
    href: "https://grabthetab.app",
    label: "Product build",
    description:
      "A consumer-facing app experience designed around a simple, memorable behavior: making it easier to split and settle a tab."
  },
  {
    name: "Klaus for Ward 3",
    href: "https://klaus4ward3.com",
    label: "Campaign website",
    description:
      "A candidate site built to make priorities, credibility, and action paths immediately clear for voters and supporters."
  }
];

type FormState = "idle" | "submitting" | "success" | "error";

export default function HomePage() {
  const [formState, setFormState] = useState<FormState>("idle");

  async function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setFormState("submitting");

    const form = event.currentTarget;
    const formData = new FormData(form);

    const response = await fetch("/api/integrations/contact", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        firstName: formData.get("firstName"),
        lastName: formData.get("lastName"),
        email: formData.get("email"),
        phone: formData.get("phone"),
        message: formData.get("message")
      })
    });

    if (response.ok) {
      form.reset();
      setFormState("success");
      return;
    }

    setFormState("error");
  }

  return (
    <AppShell>
      <main>
        <section className="relative overflow-hidden border-b border-[var(--border)]">
          <div className="absolute inset-x-0 top-0 h-48 bg-[linear-gradient(90deg,rgba(15,118,110,0.16),rgba(180,139,53,0.16),rgba(198,93,70,0.12))]" />
          <div className="relative mx-auto grid max-w-7xl gap-12 px-5 py-16 sm:px-8 md:py-24 lg:grid-cols-[1.08fr_0.92fr] lg:items-end">
            <div className="space-y-8">
              <div className="inline-flex items-center gap-2 border border-[var(--border)] bg-white px-3 py-1 text-sm text-[var(--muted)]">
                <Sparkles aria-hidden="true" size={16} className="text-[var(--gold)]" />
                AI-first media consulting for modern organizations
              </div>

              <div className="space-y-5">
                <h1 className="max-w-4xl text-5xl font-semibold leading-[1.02] tracking-normal text-[var(--foreground)] sm:text-6xl lg:text-7xl">
                  Rebuild the digital parts of your business so they finally work like an advantage.
                </h1>
                <p className="max-w-2xl text-lg leading-8 text-[var(--muted)]">
                  Forteress Media helps teams rethink websites, apps, content systems, and AI-enabled workflows with the strategy to know what matters and the implementation taste to ship it well.
                </p>
              </div>

              <div className="flex flex-wrap gap-3">
                <Button asChild>
                  <Link href="#contact">
                    Start a project
                    <ArrowRight aria-hidden="true" size={18} />
                  </Link>
                </Button>
                <Button asChild variant="secondary">
                  <Link href="#projects">See proof</Link>
                </Button>
              </div>
            </div>

            <div className="grid gap-4 border border-[var(--border)] bg-[rgba(255,255,255,0.72)] p-5 shadow-[0_24px_70px_rgba(23,21,19,0.08)] backdrop-blur">
              <div className="flex items-center justify-between border-b border-[var(--border)] pb-4">
                <p className="text-sm font-semibold uppercase text-[var(--muted)]">Where I help</p>
                <span className="size-3 bg-[var(--coral)]" />
              </div>
              {["Legacy site needs a sharper story", "App idea needs a usable first version", "Team needs AI workflows that make sense", "Campaign or launch needs a reliable web presence"].map((item) => (
                <div className="flex items-start gap-3 bg-white p-4" key={item}>
                  <CheckCircle2 aria-hidden="true" size={19} className="mt-0.5 shrink-0 text-[var(--accent)]" />
                  <p className="text-base font-medium leading-6">{item}</p>
                </div>
              ))}
            </div>
          </div>
        </section>

        <section className="mx-auto max-w-7xl px-5 py-16 sm:px-8 md:py-20" id="services">
          <div className="mb-10 flex max-w-3xl flex-col gap-3">
            <p className="text-sm font-semibold uppercase text-[var(--accent)]">Services</p>
            <h2 className="text-3xl font-semibold leading-tight sm:text-4xl">Clear strategy, strong execution, and digital work that feels useful on day one.</h2>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            {services.map((service) => {
              const Icon = service.icon;
              return (
                <article className="border border-[var(--border)] bg-white p-6" key={service.title}>
                  <Icon aria-hidden="true" size={24} className="mb-8 text-[var(--accent)]" />
                  <h3 className="text-xl font-semibold">{service.title}</h3>
                  <p className="mt-3 leading-7 text-[var(--muted)]">{service.description}</p>
                </article>
              );
            })}
          </div>
        </section>

        <section className="bg-[var(--accent-deep)] text-white">
          <div className="mx-auto grid max-w-7xl gap-10 px-5 py-16 sm:px-8 md:grid-cols-[0.85fr_1.15fr] md:py-20">
            <div>
              <p className="text-sm font-semibold uppercase text-[#d9c58b]">How it works</p>
              <h2 className="mt-3 text-3xl font-semibold leading-tight sm:text-4xl">A practical path from fuzzy problem to launched product.</h2>
            </div>
            <div className="grid gap-3">
              {process.map((step, index) => (
                <div className="grid grid-cols-[3rem_1fr] items-center border border-white/16 bg-white/6 p-4" key={step}>
                  <span className="text-sm font-semibold text-[#d9c58b]">{String(index + 1).padStart(2, "0")}</span>
                  <p className="text-lg font-medium">{step}</p>
                </div>
              ))}
            </div>
          </div>
        </section>

        <section className="mx-auto max-w-7xl px-5 py-16 sm:px-8 md:py-20" id="projects">
          <div className="mb-8 flex flex-col justify-between gap-5 md:flex-row md:items-end">
            <div className="max-w-3xl">
              <p className="text-sm font-semibold uppercase text-[var(--accent)]">Selected work</p>
              <h2 className="mt-3 text-3xl font-semibold leading-tight sm:text-4xl">Proof that the strategy can become something real.</h2>
            </div>
            <p className="max-w-md leading-7 text-[var(--muted)]">
              A small sample of delivered work across product, campaign, and modern web experiences.
            </p>
          </div>

          <div className="flex snap-x gap-4 overflow-x-auto pb-4">
            {projects.map((project) => (
              <a
                className="group min-w-[82%] snap-start border border-[var(--border)] bg-white p-6 transition hover:-translate-y-1 hover:shadow-[0_20px_50px_rgba(23,21,19,0.09)] sm:min-w-[28rem]"
                href={project.href}
                key={project.name}
                rel="noreferrer"
                target="_blank"
              >
                <div className="mb-12 flex items-center justify-between">
                  <span className="bg-[var(--surface-warm)] px-3 py-1 text-sm font-medium text-[var(--muted)]">{project.label}</span>
                  <ExternalLink aria-hidden="true" size={19} className="text-[var(--muted)] transition group-hover:text-[var(--accent)]" />
                </div>
                <h3 className="text-2xl font-semibold">{project.name}</h3>
                <p className="mt-4 leading-7 text-[var(--muted)]">{project.description}</p>
              </a>
            ))}
          </div>
        </section>

        <section className="border-t border-[var(--border)] bg-white" id="contact">
          <div className="mx-auto grid max-w-7xl gap-10 px-5 py-16 sm:px-8 md:py-20 lg:grid-cols-[0.8fr_1.2fr]">
            <div className="space-y-7">
              <div>
                <p className="text-sm font-semibold uppercase text-[var(--accent)]">Contact</p>
                <h2 className="mt-3 text-3xl font-semibold leading-tight sm:text-4xl">Tell me what you want to rebuild.</h2>
                <p className="mt-4 leading-7 text-[var(--muted)]">
                  Share the short version. I’ll follow up to understand goals, timing, and where the highest-value first move might be.
                </p>
              </div>
              <div className="grid gap-3 text-sm">
                <a className="flex items-center gap-3 border border-[var(--border)] p-4" href="mailto:contact@forteressmedia.com">
                  <Mail aria-hidden="true" size={18} className="text-[var(--accent)]" />
                  contact@forteressmedia.com
                </a>
                <a className="flex items-center gap-3 border border-[var(--border)] p-4" href="tel:+16124701881">
                  <Phone aria-hidden="true" size={18} className="text-[var(--accent)]" />
                  612-470-1881
                </a>
              </div>
            </div>

            <form className="grid gap-4 border border-[var(--border)] bg-[var(--background)] p-5 sm:grid-cols-2 sm:p-6" onSubmit={handleSubmit}>
              <label className="grid gap-2 text-sm font-medium">
                First name
                <input className="h-12 border border-[var(--border)] bg-white px-3 outline-none focus:border-[var(--accent)]" name="firstName" required />
              </label>
              <label className="grid gap-2 text-sm font-medium">
                Last name
                <input className="h-12 border border-[var(--border)] bg-white px-3 outline-none focus:border-[var(--accent)]" name="lastName" required />
              </label>
              <label className="grid gap-2 text-sm font-medium">
                Email
                <input className="h-12 border border-[var(--border)] bg-white px-3 outline-none focus:border-[var(--accent)]" name="email" required type="email" />
              </label>
              <label className="grid gap-2 text-sm font-medium">
                Phone
                <input className="h-12 border border-[var(--border)] bg-white px-3 outline-none focus:border-[var(--accent)]" name="phone" required type="tel" />
              </label>
              <label className="grid gap-2 text-sm font-medium sm:col-span-2">
                Message
                <textarea className="min-h-36 resize-y border border-[var(--border)] bg-white p-3 outline-none focus:border-[var(--accent)]" name="message" required />
              </label>
              <div className="flex flex-col gap-3 sm:col-span-2 sm:flex-row sm:items-center">
                <Button disabled={formState === "submitting"} type="submit">
                  {formState === "submitting" ? "Sending..." : "Send message"}
                  <Send aria-hidden="true" size={17} />
                </Button>
                {formState === "success" && <p className="text-sm font-medium text-[var(--accent)]">Thanks. Your message has been sent.</p>}
                {formState === "error" && <p className="text-sm font-medium text-[var(--coral)]">Something went wrong. Email or call me directly.</p>}
              </div>
            </form>
          </div>
        </section>
      </main>
    </AppShell>
  );
}
