import { Slot } from "@radix-ui/react-slot";
import { clsx } from "clsx";
import { twMerge } from "tailwind-merge";

type ButtonProps = React.ButtonHTMLAttributes<HTMLButtonElement> & {
  asChild?: boolean;
  variant?: "primary" | "secondary";
};

export function Button({ asChild, className, variant = "primary", ...props }: ButtonProps) {
  const Component = asChild ? Slot : "button";

  return (
    <Component
      className={twMerge(
        clsx(
          "inline-flex h-11 items-center justify-center gap-2 border px-5 text-sm font-semibold transition-colors",
          "focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--accent)]",
          variant === "primary" &&
            "border-[var(--accent)] bg-[var(--accent)] text-[var(--accent-foreground)] hover:bg-[#0d514b]",
          variant === "secondary" &&
            "border-[var(--border)] bg-white text-[var(--foreground)] hover:bg-[#f1eee6]"
        ),
        className
      )}
      {...props}
    />
  );
}
